const candidates = Array.isArray($json.candidates) ? $json.candidates : [];
const landlordId = $item(0).$node["Expand Landlords"].json.landlordId ?? null;
const landlordName = $item(0).$node["Expand Landlords"].json.landlordName ?? null;
const now = new Date().toISOString();

if (candidates.length === 0) {
  return [{
    json: {
      landlordId,
      landlordName,
      runAt: now,
      noCandidate: true
    }
  }];
}

return candidates.map((candidate) => ({
  json: {
    ...candidate,
    landlordId: candidate.landlordId || landlordId,
    landlordName: candidate.landlordName || landlordName,
    runAt: now,
    noCandidate: false
  }
}));

const item = $json;

let template = 'friendly';
let needsLandlordAlert = false;

if (item.overdueDays >= 7) {
  template = 'legal_notice';
  needsLandlordAlert = true;
} else if (item.overdueDays >= 3) {
  template = 'firm_overdue';
  needsLandlordAlert = true;
} else if (item.overdueDays >= 1) {
  template = 'overdue';
} else if (item.daysToDue <= 1) {
  template = 'due_tomorrow';
} else if (item.daysToDue <= 3) {
  template = 'due_3_days';
}

return [{
  json: {
    ...item,
    template,
    needsLandlordAlert
  }
}];

const records = $input.all().map((row) => row.json);
const runStamp = $now.toISO();
const grouped = new Map();

for (const record of records) {
  const landlordId = record.landlordId ?? 'unknown';
  const current = grouped.get(landlordId) || {
    landlordId: record.landlordId ?? null,
    remindersSet: 0,
    overdueAlerts: 0,
  };

  if (!record.noCandidate) {
    current.remindersSet += 1;
  }

  if (record.needsLandlordAlert) {
    current.overdueAlerts += 1;
  }

  grouped.set(landlordId, current);
}

return Array.from(grouped.values()).map((summary) => ({
  json: {
    workflowName: 'rent-reminders',
    trigger: 'cron',
    outcome: summary.remindersSet > 0 ? 'success' : 'skipped',
    landlordId: summary.landlordId,
    correlationId: $execution.id,
    idempotencyKey: `rent-reminders:batch:${summary.landlordId}:${runStamp}:${$execution.id}`,
    details: {
      batchMode: true,
      remindersSet: summary.remindersSet,
      overdueAlerts: summary.overdueAlerts,
      runAt: runStamp
    }
  }
}));
